scripts.script:
// Weave (#1): a third-party plugin registered ONCE, globally, by name. It
// never touches internal state: it subscribes to the 'draw' lifecycle hook
// and paints into its own sandboxed layer using the api (scales, data, theme,
// emit). Activate it per-chart via the top-level plugins array.
ApexCharts.registerPlugin({
  name: 'mean-line',
  apiVersion: 1,
  setup(api) {
    api.on('draw', function (ctx) {
      var scales = ctx.scales
      var data = ctx.data
      if (!scales || !data || !data.length) return

      var layer = api.layer({ z: 'front' })
      layer.clear()

      var series = data.filter(function (s) { return !s.hidden })[0]
      if (!series || !series.points.length) return

      var sum = 0
      var n = 0
      series.points.forEach(function (p) {
        if (p.y != null) { sum += p.y; n++ }
      })
      if (!n) return

      var mean = sum / n
      var y = scales.y(mean)
      var accent = api.theme.token('accent') || '#0e9d9a'

      layer.line({
        x1: 0, y1: y, x2: scales.gridWidth, y2: y,
        stroke: accent, width: 2, dash: 5,
      })
      layer.text({
        x: scales.gridWidth - 6, y: y - 7,
        text: 'mean ' + mean.toFixed(1),
        color: accent, size: 12, anchor: 'end', weight: 600,
      })

      // hand the computed value back to the page via a custom event; it
      // fires namespaced as 'plugin:mean-line:meanComputed' so plugin events
      // can never collide with the chart's internal lifecycle events
      api.emit('meanComputed', { value: mean })
    })
  },
})

function randomSeries() {
  var d = []
  for (var i = 0; i < 8; i++) d.push(Math.round(20 + Math.random() * 80))
  return d
}

html:
New data Mean line drawn by the plugin. Press New data to recompute.
{{ charts[0] }}
The dashed mean line is not part of the chart: it is drawn by a plugin registered with ApexCharts.registerPlugin({ name, setup }) and activated via plugins: [{ name: 'mean-line' }]. On every draw hook the plugin reads api.data, converts the mean to a pixel with api.scales.y(), paints into its own api.layer(), and reports the value back through api.emit(). Press New data: the plugin recomputes and redraws.

vanilla-js-script:
var readout = document.getElementById('readout')

chart.addEventListener('plugin:mean-line:meanComputed', function (c, payload) {
  var detail = payload && payload.value != null ? payload : (c && c.value != null ? c : null)
  var v = detail ? detail.value : null
  if (v != null) {
    readout.innerHTML = 'plugin mean-line emitted: mean = ' + v.toFixed(1) + ''
  }
})

document.getElementById('newData').addEventListener('click', function () {
  chart.updateSeries([{ name: 'Value', data: randomSeries() }])
})

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id. Poll until it exists, then wire the same UI the vanilla build
  // does. (The mean-line plugin is registered ONCE in the shared head script,
  // before any chart is created, and randomSeries lives there too.)
  let chart
  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('weaveChart')
    if (!chart) return
    window.clearInterval(timer)

    const readout = document.getElementById('readout')

    chart.addEventListener('plugin:mean-line:meanComputed', (c, payload) => {
      const detail = payload && payload.value != null ? payload : (c && c.value != null ? c : null)
      const v = detail ? detail.value : null
      if (v != null) {
        readout.innerHTML = 'plugin mean-line emitted: mean = ' + v.toFixed(1) + ''
      }
    })

    document.getElementById('newData').addEventListener('click', () => {
      chart.updateSeries([{ name: 'Value', data: randomSeries() }])
    })
  }, 50)

  return () => {
    window.clearInterval(timer)
  }
}, [])

